interface AppConfig {
  apiUrl: string;
  timeout: number;
  retries: number;
  features: FeatureFlags;
}

interface FeatureFlags {
  darkMode: boolean;
  betaAccess: boolean;
}

export function loadConfig(): AppConfig {
  return {
    apiUrl: process.env.API_URL,  // string | undefined assigned to string
    timeout: parseInt(process.env.TIMEOUT),  // number | NaN assigned to number
    retries: process.env.RETRIES as unknown as number,  // string cast to number
    features: {
      darkMode: process.env.DARK_MODE,  // string | undefined assigned to boolean
      betaAccess: process.env.BETA === 'true'
    }
  };
}
